import React from 'react';

/**
 * LiveCare Logo — infinity/eye shape with medical cross
 * Colors match brand: blue #387afc + navy #0d1157 + orange #c0440a
 */
export default function Logo({ size = 40, showText = true, light = false }) {
  const textColor = light ? '#ffffff' : '#0d1157';
  const blueColor = '#387afc';

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
      {/* Icon mark */}
      <svg width={size} height={size * 0.6} viewBox="0 0 80 48" fill="none" xmlns="http://www.w3.org/2000/svg">
        {/* Left lobe of infinity */}
        <ellipse cx="22" cy="24" rx="18" ry="14" fill={blueColor} opacity="0.9" />
        {/* Right lobe of infinity */}
        <ellipse cx="58" cy="24" rx="18" ry="14" fill={blueColor} />
        {/* White eye/pupil center */}
        <ellipse cx="58" cy="24" rx="9" ry="9" fill="white" />
        {/* Blue iris */}
        <ellipse cx="58" cy="24" rx="5.5" ry="5.5" fill={blueColor} />
        {/* Orange plus/cross */}
        <rect x="55.5" y="20" width="5" height="2" rx="1" fill="#c0440a" />
        <rect x="57.5" y="18" width="2" height="6" rx="1" fill="#c0440a" />
        {/* Connector bridge */}
        <rect x="28" y="20" width="24" height="8" rx="4" fill={blueColor} />
      </svg>

      {showText && (
        <span style={{ fontSize: size * 0.55, fontWeight: 700, fontFamily: 'Poppins, sans-serif', lineHeight: 1 }}>
          <span style={{ color: textColor }}>Live</span>
          <span style={{ color: blueColor }}>Care</span>
        </span>
      )}
    </div>
  );
}
